public string Pluralize(string word)
{
    if (string.IsNullOrWhiteSpace(word))
    {
        return word;
    }

    return _pluralCache.GetOrAdd(word, w =>
    {
        if (_uncountables.Contains(w))
        {
            return w;
        }

        if (_irregularPlurals.TryGetValue(w, out var irregularPlural))
        {
            return irregularPlural;
        }

        return ApplyRules(_plurals, w) ?? w;
    });
}

