     /// </summary>
     /// <param name="word">The word to singularize.</param>
     /// <returns>The singular form of the word.</returns>
     public string Singularize(string word)
     {
         if (string.IsNullOrWhiteSpace(word))
         {
             return word;
         }

         return _singularCache.GetOrAdd(word, w =>
         {
             if (_uncountables.Contains(w))
             {
                 return w;
             }

             if (_irregularSingulars.TryGetValue(w, out var irregularSingular))
